proof_block:
// Pull both ensures into the proof context under their hypotheses so that
// the disjoint-trigger forall/exists quantifiers inside the (now-revealed)
// `next_set_request_postconditions` get materialised against *both* runs.
//
// `next_set_request_preconditions` already gives us that
// `pre_self_.received_packet` is `Some(cpacket)` with `cpacket.msg` a
// `Message::SetRequest`.  Naming the cpacket explicitly stabilises the
// witness used by `next_set_request(pre@, post_i@, cpacket@, abstractify(r_i@))`
// in both runs.
let cpacket = pre_self_.received_packet.unwrap();
assert(pre_self_.received_packet is Some);
assert(pre_self_.received_packet.unwrap() == cpacket);
assert(cpacket.msg is Message);
assert(cpacket.msg.arrow_Message_m() is SetRequest);
assert(pre_self_@.received_packet is Some);
assert(pre_self_@.received_packet.unwrap() == cpacket@);

// Surface every structural conjunct of `next_set_request_postconditions`
// under its hypothesis.  Each implication is a direct unfolding of the
// already-revealed closed spec, so Verus discharges it propositionally.

// (a) Abstractability / outbound-validity / per-index msg-shape forall.
assert(post1_self_.next_set_request_postconditions(pre_self_, r1@) ==>
    cpacket_seq_is_abstractable(r1@));
assert(post2_self_.next_set_request_postconditions(pre_self_, r2@) ==>
    cpacket_seq_is_abstractable(r2@));
assert(post1_self_.next_set_request_postconditions(pre_self_, r1@) ==>
    outbound_packet_seq_is_valid(r1@));
assert(post2_self_.next_set_request_postconditions(pre_self_, r2@) ==>
    outbound_packet_seq_is_valid(r2@));
assert(post1_self_.next_set_request_postconditions(pre_self_, r1@) ==>
    outbound_packet_seq_has_correct_srcs(r1@, pre_self_.constants.me@));
assert(post2_self_.next_set_request_postconditions(pre_self_, r2@) ==>
    outbound_packet_seq_has_correct_srcs(r2@, pre_self_.constants.me@));

// (b) Re-assert each disjoint-trigger per-index `forall|i|` under its
//     hypothesis.  `#[trigger] r1@[i].msg` vs `#[trigger] r2@[i].msg` line
//     up only when both quantifiers materialise at the same proof point.
assert(post1_self_.next_set_request_postconditions(pre_self_, r1@) ==>
    (forall|i: int| 0 <= i && i < r1@.len() ==>
        (#[trigger] r1@[i].msg) is Message || r1@[i].msg is Ack));
assert(post2_self_.next_set_request_postconditions(pre_self_, r2@) ==>
    (forall|i: int| 0 <= i && i < r2@.len() ==>
        (#[trigger] r2@[i].msg) is Message || r2@[i].msg is Ack));

// (c) The LSHT `=~=` identity for each run.
assert(post1_self_.next_set_request_postconditions(pre_self_, r1@) ==>
    abstractify_seq_of_cpackets_to_set_of_sht_packets(r1@) =~=
    extract_packets_from_lsht_packets(
        abstractify_outbound_packets_to_seq_of_lsht_packets(r1@)));
assert(post2_self_.next_set_request_postconditions(pre_self_, r2@) ==>
    abstractify_seq_of_cpackets_to_set_of_sht_packets(r2@) =~=
    extract_packets_from_lsht_packets(
        abstractify_outbound_packets_to_seq_of_lsht_packets(r2@)));

// (d) Surface the abstract step relation `next_set_request(pre@, post_i@,
//     cpacket@, out_i)` for each run — this is the core conjunct that ties
//     the spec-determined post-state fields (delegation_map, num_delegations)
//     and the existential over (sm, replym, should_send) together.
assert(post1_self_.next_set_request_postconditions(pre_self_, r1@) ==>
    next_set_request(pre_self_@, post1_self_@, cpacket@,
        abstractify_seq_of_cpackets_to_set_of_sht_packets(r1@)));
assert(post2_self_.next_set_request_postconditions(pre_self_, r2@) ==>
    next_set_request(pre_self_@, post2_self_@, cpacket@,
        abstractify_seq_of_cpackets_to_set_of_sht_packets(r2@)));

// (e) Per-field abstract post-state equalities with `pre_self_@` on every
//     spec-determined component.  These are direct conjuncts of either
//     `host_state_common_postconditions` (constants, ...) or of the
//     `next_set_request` step relation (delegation_map, num_delegations).
assert(post1_self_.next_set_request_postconditions(pre_self_, r1@) ==>
    post1_self_@.delegation_map == pre_self_@.delegation_map);
assert(post2_self_.next_set_request_postconditions(pre_self_, r2@) ==>
    post2_self_@.delegation_map == pre_self_@.delegation_map);
assert(post1_self_.next_set_request_postconditions(pre_self_, r1@) ==>
    post1_self_@.num_delegations == pre_self_@.num_delegations);
assert(post2_self_.next_set_request_postconditions(pre_self_, r2@) ==>
    post2_self_@.num_delegations == pre_self_@.num_delegations);
assert(post1_self_.next_set_request_postconditions(pre_self_, r1@) ==>
    post1_self_@.constants == pre_self_@.constants);
assert(post2_self_.next_set_request_postconditions(pre_self_, r2@) ==>
    post2_self_@.constants == pre_self_@.constants);
assert(post1_self_.next_set_request_postconditions(pre_self_, r1@) ==>
    post1_self_@.received_packet is None);
assert(post2_self_.next_set_request_postconditions(pre_self_, r2@) ==>
    post2_self_@.received_packet is None);

// (f) Cross-run abstract-state field equalities, chained through `pre_self_@`.
//     These build the AbstractHostState extensionality witness for
//     `post1_self_@ == post2_self_@` on the spec-pinned fields.
assert((post1_self_.next_set_request_postconditions(pre_self_, r1@) &&
        post2_self_.next_set_request_postconditions(pre_self_, r2@)) ==>
    post1_self_@.delegation_map == post2_self_@.delegation_map);
assert((post1_self_.next_set_request_postconditions(pre_self_, r1@) &&
        post2_self_.next_set_request_postconditions(pre_self_, r2@)) ==>
    post1_self_@.num_delegations == post2_self_@.num_delegations);
assert((post1_self_.next_set_request_postconditions(pre_self_, r1@) &&
        post2_self_.next_set_request_postconditions(pre_self_, r2@)) ==>
    post1_self_@.constants == post2_self_@.constants);
assert((post1_self_.next_set_request_postconditions(pre_self_, r1@) &&
        post2_self_.next_set_request_postconditions(pre_self_, r2@)) ==>
    post1_self_@.received_packet == post2_self_@.received_packet);
